const PROCESSING_FEE = 5;

type Scenario = { steps: { items: unknown[] }[] };

export const runScenario = (input: unknown): unknown => {
  const items = (input as Scenario).steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  return { results: [{ premium: 115 }] };
};
